const item = $input.first().json;
const raw = item.message?.content || '{}';
let scoring = {};
try {
  const match = raw.match(/\{[\s\S]*\}/);
  scoring = JSON.parse(match[0]);
} catch(e) {
  scoring = { icp_score: 0, icp_segment: 'COLD', fit_reasons: [], error: true };
}

return [{ json: {
  ...item,
  icp_score: scoring.icp_score,
  icp_segment: scoring.icp_segment,
  fit_reasons: scoring.fit_reasons,
  pain_points: scoring.pain_points,
  automation_opportunities: scoring.automation_opportunities,
  personalization_hook: scoring.personalization_hook,
  recommended_service: scoring.recommended_service,
  email_subject: scoring.email_subject,
  email_tone: scoring.email_tone,
  disqualify_reason: scoring.disqualify_reason
}}];

