const rows = $input.all();
const now = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);

const thisWeek = rows.filter(r => new Date(r.json.email_sent_at) >= weekAgo);
const hot = thisWeek.filter(r => r.json.segment === 'HOT').length;
const warm = thisWeek.filter(r => r.json.segment === 'WARM').length;
const cold = thisWeek.filter(r => r.json.segment === 'COLD').length;
const byService = {};
thisWeek.forEach(r => { byService[r.json.service] = (byService[r.json.service] || 0) + 1; });

return [{ json: {
  week_total: thisWeek.length,
  hot_leads: hot,
  warm_leads: warm,
  cold_leads: cold,
  by_service: byService,
  top_industries: [...new Set(thisWeek.map(r => r.json.company))].slice(0, 5),
  avg_score: thisWeek.length ? Math.round(thisWeek.reduce((s, r) => s + (parseInt(r.json.icp_score) || 0), 0) / thisWeek.length) : 0,
  week_start: weekAgo.toISOString().split('T')[0],
  week_end: now.toISOString().split('T')[0]
}}];

